// import Loadable from "@loadable/component";
import { Power0, Power3, TimelineMax } from "gsap";
import $ from "jquery";
// import React from "react";
// import ReactDOM from "react-dom";
// import { SpinnerFlexButton as Loading } from "react-labs/src/components/Util";

//EL's
const $bg = $(".js-bg");
const $heading = $(".js-heading");
const $logoInverted = $(".js-logo-inverted");
const $logoLeft = $(".js-logo-left");
const $logoLeftInner = $logoLeft.find("span");
const $logo = $(".js-logo");
const $logoRight = $(".js-logo-right");
const $logoRightInner = $logoRight.find("span");
const $textContainer = $(".js-text-container");
const $text = $(".js-text");
const $restartButton = $(".js-restart");

//TIMELINE
const plTl = new TimelineMax({
  //paused: true,
  //delay: 3,
  onComplete: () => {
    $restartButton.addClass("is-active");
    //
    console.log("onComplete");
    //
    $(".side-menu").show();
    // const App = Loadable(() => import("react-labs/src/App"), {
    //   fallback: <Loading />
    // });
    // ReactDOM.render(<App />, document.getElementById("root"));
    //
  }
});

plTl
  .add("start")
  .fromTo(
    $bg,
    0.4,
    {
      autoAlpha: 0
    },
    {
      autoAlpha: 1,
      ease: Power3.easeOut
    },
    "start"
  )

  .fromTo(
    $bg,
    1.8,
    {
      scale: 2,
      x: "-70%"
    },
    {
      scale: 1,
      x: "0%",
      ease: Power3.easeOut
    },
    "start"
  )
  .to(
    $heading,
    0.6,
    {
      y: 0,
      ease: Power3.easeOut
    },
    "-=0.4",
    "start"
  )
  .add("shiftRight", "+=0.4")
  .to(
    $logoInverted,
    0.8,
    {
      x: "50%",
      ease: Power3.easeOut
    },
    "shiftRight"
  )

  .to(
    $bg,
    1,
    {
      x: "-=7%",
      ease: Power3.easeOut
    },
    "shiftRight"
  )
  .to(
    $heading,
    0.8,
    {
      x: "+=35%",
      ease: Power3.easeOut
    },
    "shiftRight"
  )
  .to(
    $logoRightInner,
    0.8,
    {
      x: "-100%",
      ease: Power3.easeOut
    },
    "shiftRight"
  )
  .to(
    $logoLeftInner,
    0.8,
    {
      x: "100%",
      ease: Power3.easeOut
    },
    "shiftRight"
  )
  .to(
    [$logoRight, $logoLeft],
    0.8,
    {
      width: 0,
      padding: 0,
      ease: Power3.easeOut
    },
    "shiftRight"
  )
  .add("shiftLeft")
  .to(
    $heading,
    0.8,
    {
      x: "-=50%",
      ease: Power3.easeOut
    },
    "shiftLeft"
  )
  .to(
    $textContainer,
    0.8,
    {
      scaleX: 1,
      ease: Power3.easeOut
    },
    "shiftLeft"
  )
  .to(
    $text,
    1,
    {
      autoAlpha: 1,
      x: 0,
      ease: Power3.easeOut
    },
    "shiftLeft"
  )
  .to(
    $bg,
    3,
    {
      x: "-=5%",
      ease: Power0.easeNone
    },
    "shiftLeft"
  )
  .to(
    $logoInverted,
    2,
    {
      x: "-=2.5%",
      ease: Power0.easeNone
    },
    "shiftLeft"
  );

$restartButton.on("click", () => {
  plTl.restart();
});
